  <polygon points="179,220 191,220 185,229" fill="#3f3f46"/>
  <line x1="515" y1="188" x2="515" y2="226" stroke="#3f3f46" stroke-width="2"/>
  <polygon points="509,220 521,220 515,229" fill="#3f3f46"/>
  <rect x="35" y="230" width="300" height="78" rx="10" fill="#161619" stroke="#3f3f46" stroke-width="1.5"/>
